import{_ as a,H as e,f as r,i as n}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"未来系列规划","description":"","frontmatter":{},"headers":[],"relativePath":"未来系列规划.md","filePath":"未来系列规划.md","lastUpdated":1778649484000}'),o={name:"未来系列规划.md"};function i(s,t,l,d,g,h){return e(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="未来系列规划" tabindex="-1">未来系列规划 <a class="header-anchor" href="#未来系列规划" aria-label="Permalink to &quot;未来系列规划&quot;">​</a></h1><p>把已写完的系列之外、值得新开的方向存这里。 当前知识图已经覆盖 Web / AI / AI Infra / Backend / Flutter / Claude / Git / Algorithm / Math for CS / System Design / Distributed / Network / OS / Rust / Go / Security / Interpreter / Data Engineering / DevOps / Terminal 二十个主系列。后续重点不再是&quot;补基础缺口&quot;,而是<strong>项目化消化 + 细分专题 + 兴趣型方向</strong>。</p><hr><h2 id="已完成的系列" tabindex="-1">已完成的系列 <a class="header-anchor" href="#已完成的系列" aria-label="Permalink to &quot;已完成的系列&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系列</th><th>篇数</th><th>主题</th></tr></thead><tbody><tr><td>webLearning</td><td>50</td><td>React / Vue / Angular / Solid + 基础 + 工程 + 进阶 + 专题</td></tr><tr><td>aiLearning</td><td>41</td><td>神经网络 / Transformer / LLM / Prompt / RAG / Agent / 多模态 / 微调 / 推理引擎</td></tr><tr><td>backendLearning</td><td>66</td><td>HTTP / Spring Boot / ElysiaJS / SQL / Redis / ES / Docker / K8s / 微服务 / SRE / 数据 / 架构专题</td></tr><tr><td>flutterLearning</td><td>43</td><td>状态管理 / Widget / 布局 / 动画 / 平台 / 性能 / 测试 / 架构 / WebRTC / CI</td></tr><tr><td>claudeLearning</td><td>30</td><td>Claude Code / Anthropic API / Agent SDK / MCP server / 设计模式</td></tr><tr><td>gitLearning</td><td>22</td><td>DAG 心智 / 分支 / rebase / reflog / 工作流 / 大仓库 / 签名安全</td></tr><tr><td>algorithmLearning</td><td>28</td><td>复杂度 / 数据结构 / 算法范式 / LRU 限流 一致性哈希 等工程实战</td></tr><tr><td>systemDesign</td><td>30</td><td>心智 / 抗压基础设施 / 经典案例 / 多机房 / 容灾 / 文档面试</td></tr><tr><td>networkLearning</td><td>40</td><td>协议栈 / IP / TCP / TLS / HTTP/2/3 / DNS / 内核网络 / 反代 / 安全 / 排障</td></tr><tr><td>osLearning</td><td>28</td><td>用户态内核态 / 系统调用 / 虚拟内存 / 进程线程 / 锁 / 调度 / IO / 容器 / eBPF</td></tr><tr><td>rustLearning</td><td>30</td><td>所有权与借用 / 生命周期 / 泛型与Trait / 智能指针 / 无畏并发 / Tokio异步 / 实战</td></tr><tr><td>goLearning</td><td>30</td><td>Go Modules / 类型系统 / 并发 / net/http / Gin / 数据库 / 微服务 / Docker / K8s / 性能剖析</td></tr><tr><td>securityLearning</td><td>30</td><td>心智 / 密码学 / Web 攻防 / 二进制内存 / 渗透红蓝紫 / 供应链 / SDL / 容器云 / AI 安全</td></tr><tr><td>interpreterLearning</td><td>30</td><td>解释器 vs 编译器 vs JIT / Mochi 玩具语言 / 词法语法 / 树遍历 / 字节码 VM / GC / 真实语言剖析</td></tr><tr><td>distributedLearning</td><td>30</td><td>故障模型 / 时钟 / Paxos / Raft / 一致性模型 / 分布式事务 / Spanner / Gossip / 选主与租约</td></tr><tr><td>devopsLearning</td><td>34</td><td>SRE / 可观测性 / Prometheus / 日志 / Tracing / SLO / CI/CD / GitOps / IaC / 事故响应</td></tr><tr><td>dataEngineering</td><td>32</td><td>OLTP/OLAP / ETL/ELT / 数据湖 / Iceberg / Spark / Flink / dbt / CDC / RAG 数据管道 / 数据质量</td></tr><tr><td>terminalLearning</td><td>30</td><td>TTY / Shell / zsh / fzf / tmux / Neovim / Helix / dotfiles / Nix / Devcontainer / Claude Code 工作流</td></tr><tr><td>aiInfraLearning</td><td>30</td><td>GPU / 显存 / vLLM / SGLang / KV Cache / 并行训练 / 量化 / Ray / K8s GPU / Slurm / 成本吞吐</td></tr><tr><td>mathForCS</td><td>30</td><td>数值精度 / 线性代数 / 概率统计 / 信息论 / 微积分与优化 / 图论 / 数论 / 马尔可夫链</td></tr></tbody></table><hr><h2 id="当前结论" tabindex="-1">当前结论 <a class="header-anchor" href="#当前结论" aria-label="Permalink to &quot;当前结论&quot;">​</a></h2><p><strong>已开系列全部完成</strong>,当前目录里没有&quot;写了一半但没补完&quot;的主系列。</p><p>下一步如果继续扩知识图,优先级变成:</p><ol><li><strong>项目化消化</strong>:用一个真实项目把 AI / Backend / Data / DevOps / Terminal 串起来,否则知识会停在文档层。</li><li><strong>细分专题</strong>:图形学、音视频、嵌入式、独立开发、技术写作这些方向按兴趣开,不再是体系缺口。</li><li><strong>维护与发布</strong>:保持 GitHub Pages 入口、目录导航、规划文档和新增系列同步。</li></ol><hr><h2 id="一、补完整知识图-已完成" tabindex="-1">一、补完整知识图(已完成) <a class="header-anchor" href="#一、补完整知识图-已完成" aria-label="Permalink to &quot;一、补完整知识图(已完成)&quot;">​</a></h2><p>这些是原先最重要的基础缺口,现在已经补齐。</p><h3 id="a-systemdesign-系统设计-⭐⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">A. systemDesign / 系统设计 ⭐⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#a-systemdesign-系统设计-⭐⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;A. systemDesign / 系统设计 ⭐⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>12306 / Twitter / 微信 / 短链 / Feed / 直播 怎么设计?</p></blockquote><p>backendLearning 教了&quot;用什么工具&quot;,systemDesign 教&quot;工具怎么组合应对真实流量&quot;。 <strong>面试 + 架构师必经</strong>,backend 知识缺这一层就上不去。</p><p>已覆盖:</p><ul><li>架构基础:可用性 / 一致性 / 分区 / 缓存 / 队列 / 限流 / 熔断 / 降级</li><li>经典案例:短链、Twitter、新闻 Feed、即时通讯、视频流、网约车、秒杀、订单、支付</li><li>进阶:多机房 / 异地多活 / 容灾 / 数据迁移 / 灰度发布</li></ul><h3 id="b-algorithms-数据结构与算法-⭐⭐⭐⭐⭐-✅-2026-05-完成-28-篇" tabindex="-1">B. algorithms / 数据结构与算法 ⭐⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,28 篇)</strong> <a class="header-anchor" href="#b-algorithms-数据结构与算法-⭐⭐⭐⭐⭐-✅-2026-05-完成-28-篇" aria-label="Permalink to &quot;B. algorithms / 数据结构与算法 ⭐⭐⭐⭐⭐ ✅ **(2026/05 完成,28 篇)**&quot;">​</a></h3><blockquote><p>不是 LeetCode 刷题,是&quot;工程师真用得上的算法心智模型&quot;</p></blockquote><p>链表 / 树 / 图 / 堆 / 排序 / 动态规划 / 滑动窗口 / 二分 / 回溯 / 贪心。 <strong>面试硬通货</strong>,且写代码 / 调性能时直觉就来自这。</p><p>已覆盖:每个数据结构 + 每类经典题型 + 实战(LRU / 限流 / 一致性哈希 / 调度算法 / 布隆过滤器)。</p><h3 id="c-network-网络深入-⭐⭐⭐⭐-✅-2026-05-完成-40-篇" tabindex="-1">C. network / 网络深入 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,40 篇)</strong> <a class="header-anchor" href="#c-network-网络深入-⭐⭐⭐⭐-✅-2026-05-完成-40-篇" aria-label="Permalink to &quot;C. network / 网络深入 ⭐⭐⭐⭐ ✅ **(2026/05 完成,40 篇)**&quot;">​</a></h3><blockquote><p>webLearning 浅讲,可以深挖到 RFC 级别</p></blockquote><p>HTTP/2/3 / QUIC / TCP / TLS / DNS / WebSocket 内部 / CDN / 抓包工具 / 性能调优。 <strong>全栈工程师天花板</strong>,Web + 后端 + 移动都会受益。</p><p>已覆盖 40 篇,从链路层一路到排障方法论。</p><h3 id="d-os-操作系统-计算机系统-⭐⭐⭐⭐-✅-2026-05-完成-28-篇" tabindex="-1">D. os / 操作系统 / 计算机系统 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,28 篇)</strong> <a class="header-anchor" href="#d-os-操作系统-计算机系统-⭐⭐⭐⭐-✅-2026-05-完成-28-篇" aria-label="Permalink to &quot;D. os / 操作系统 / 计算机系统 ⭐⭐⭐⭐ ✅ **(2026/05 完成,28 篇)**&quot;">​</a></h3><blockquote><p>CSAPP 风格:进程 / 线程 / 内存 / 文件 / IO 模型 / 协程</p></blockquote><p>理解这些之后,看任何&quot;性能问题&quot;都能直接看到底。 Java GC、Node 事件循环、Flutter Isolate、Go 协程 全是这层往上长出来的。</p><p>已覆盖:系统调用、CPU、中断、虚拟内存、内存分配、cache、进程线程、IPC、锁、调度、协程、VFS、文件系统、IO 模型、epoll、io_uring、零拷贝、信号、容器、性能工具、eBPF。</p><hr><h2 id="二、新语言-新栈-挑一个真正想用的" tabindex="-1">二、新语言 / 新栈(挑一个真正想用的) <a class="header-anchor" href="#二、新语言-新栈-挑一个真正想用的" aria-label="Permalink to &quot;二、新语言 / 新栈(挑一个真正想用的)&quot;">​</a></h2><h3 id="e-rust-rust-入门-→-进阶-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">E. rust / Rust 入门 → 进阶 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#e-rust-rust-入门-→-进阶-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;E. rust / Rust 入门 → 进阶 ⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>2025 系统编程主流</p></blockquote><ul><li>所有权 / 借用 / lifetime</li><li>Trait / 泛型 / 类型体操</li><li>async / Tokio / Axum</li><li>写 CLI / WebAssembly / 嵌入式</li></ul><p>跟已有栈差异最大,<strong>学了能开新一层视野</strong>。 Linux 内核、Tauri、Cloudflare Workers、各种数据库 driver 都在用 Rust。</p><h3 id="f-go-go-入门-→-进阶-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">F. go / Go 入门 → 进阶 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#f-go-go-入门-→-进阶-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;F. go / Go 入门 → 进阶 ⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>后端 / 云原生主流</p></blockquote><ul><li>并发模型(goroutine / channel)</li><li>网络服务 / gRPC</li><li>K8s / Docker / Prometheus 都是 Go</li></ul><p>后端 / 云原生职位需求量大。比 Rust 简单一个量级,<strong>两周能出活</strong>。</p><hr><h2 id="三、纵深主题-已有领域的-地下室" tabindex="-1">三、纵深主题(已有领域的&quot;地下室&quot;) <a class="header-anchor" href="#三、纵深主题-已有领域的-地下室" aria-label="Permalink to &quot;三、纵深主题(已有领域的&quot;地下室&quot;)&quot;">​</a></h2><h3 id="g-distributed-分布式系统理论-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">G. distributed / 分布式系统理论 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#g-distributed-分布式系统理论-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;G. distributed / 分布式系统理论 ⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><p>CAP / BASE / Paxos / Raft / 2PC / Saga / 一致性哈希 / 分布式锁 / 分布式事务 / 时钟。 <strong>跟 systemDesign 互补</strong>,一个偏理论一个偏工程。</p><h3 id="h-devops-devops-sre-可观测性-⭐⭐⭐⭐-✅-2026-05-完成-34-篇" tabindex="-1">H. devops / DevOps / SRE / 可观测性 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,34 篇)</strong> <a class="header-anchor" href="#h-devops-devops-sre-可观测性-⭐⭐⭐⭐-✅-2026-05-完成-34-篇" aria-label="Permalink to &quot;H. devops / DevOps / SRE / 可观测性 ⭐⭐⭐⭐ ✅ **(2026/05 完成,34 篇)**&quot;">​</a></h3><p>监控(Prometheus / Grafana)、链路追踪(OpenTelemetry / Jaeger)、日志(Loki / ELK)、 SLO / SLA / 错误预算、混沌工程、容量规划、故障复盘。 <strong>backendLearning 后半截的延伸</strong>。</p><h3 id="i-security-安全工程-⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">I. security / 安全工程 ⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#i-security-安全工程-⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;I. security / 安全工程 ⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><p>webLearning 里写了 35 篇浅讲。深入的话: OWASP Top 10 详解、二进制 / 内存安全、密码学(对称 / 非对称 / 椭圆曲线)、 CTF 入门、渗透测试基础、供应链安全。</p><p>已覆盖六层:心智 / 威胁建模 → 密码学原语与陷阱 → Web 安全深入(XSS/CSRF/注入/SSRF/反序列化/认证) → 二进制内存安全(栈/堆/ROP/缓解/Fuzz) → 渗透与红蓝紫队 → 工程化防御(供应链/SDL/容器云/监控响应/<strong>AI 安全</strong>)。</p><h3 id="j-dataengineering-数据工程-⭐⭐⭐-✅-2026-05-完成-32-篇" tabindex="-1">J. dataEngineering / 数据工程 ⭐⭐⭐ ✅ <strong>(2026/05 完成,32 篇)</strong> <a class="header-anchor" href="#j-dataengineering-数据工程-⭐⭐⭐-✅-2026-05-完成-32-篇" aria-label="Permalink to &quot;J. dataEngineering / 数据工程 ⭐⭐⭐ ✅ **(2026/05 完成,32 篇)**&quot;">​</a></h3><p>Spark / Flink / Airflow / dbt / Iceberg / 数据湖 / 实时数仓。 AI 时代数据工程比以前更热,<strong>和 AI 系列正好接上</strong>。</p><p>已覆盖:OLTP/OLAP、ETL/ELT、Lambda/Kappa、数据契约、列存、数据湖、Iceberg、Hudi/Delta、Lakehouse、Catalog、Spark、Flink、编排、dbt、CDC、向量数据库、RAG 数据管道、特征平台、数据质量与可观测、未来趋势。</p><h3 id="l-aiinfra-llm-系统工程-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">L. aiInfra / LLM 系统工程 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#l-aiinfra-llm-系统工程-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;L. aiInfra / LLM 系统工程 ⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>aiLearning 41 篇偏「模型一侧」,这一层补「<strong>生产一侧</strong>」</p></blockquote><ul><li>推理引擎内部:vLLM / SGLang / TensorRT-LLM / PagedAttention / KV cache / 连续批处理</li><li>训练框架:Megatron / DeepSpeed / FSDP / 张量并行 / 流水并行 / ZeRO</li><li>调度与平台:Ray / Slurm / Kubeflow / GPU 资源调度</li><li>量化与压缩:GPTQ / AWQ / FP8 / 投机解码</li><li>端到端:从 GPU 选型到推理服务到成本控制</li></ul><p><strong>和 dataEngineering 接成完整 AI 工程链</strong>:数据 → 训练 → 推理 → 评测。</p><h3 id="m-mathforcs-程序员的数学-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">M. mathForCS / 程序员的数学 ⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#m-mathforcs-程序员的数学-⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;M. mathForCS / 程序员的数学 ⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>aiLearning 第 2 篇只起了个头,真要往深了走 RAG 评估、量化、推理优化、分布式都绕不开</p></blockquote><ul><li>线性代数:向量空间 / 矩阵分解(SVD / PCA / 特征值)/ 张量</li><li>概率与统计:贝叶斯 / 极大似然 / 假设检验 / 蒙特卡洛</li><li>信息论:熵 / 互信息 / KL 散度 / 编码下界</li><li>凸优化:梯度下降 / 牛顿法 / 拉格朗日对偶</li><li>离散数学:图论 / 组合 / 数论(签名 / 密码学用)</li><li>工程导向:不证明,只讲「为什么这个公式在工程里有用」</li></ul><p><strong>支撑 aiLearning / securityLearning / algorithmLearning 三个系列的地下室</strong>。</p><h3 id="n-terminallearning-终端工程-⭐⭐⭐⭐-2026-05-完成-30-篇初稿" tabindex="-1">N. terminalLearning / 终端工程 ⭐⭐⭐⭐ <strong>(2026/05 完成,30 篇初稿)</strong> <a class="header-anchor" href="#n-terminallearning-终端工程-⭐⭐⭐⭐-2026-05-完成-30-篇初稿" aria-label="Permalink to &quot;N. terminalLearning / 终端工程 ⭐⭐⭐⭐ **(2026/05 完成,30 篇初稿)**&quot;">​</a></h3><blockquote><p>Claude Code 已经是日常,但终端工作流的肌肉记忆没系统化过</p></blockquote><ul><li>心智:tty / pty / shell / 终端模拟器 / Unix 哲学</li><li>Shell 选型:bash / zsh / fish / 提示符 / 补全 / 历史(fzf / atuin)</li><li>CLI 工具链:grep-sed-awk → rg / fd / bat,fzf,jq,ssh,curl</li><li>Multiplexer + 编辑器:tmux / Zellij / Vim / Neovim / Helix</li><li>Dotfiles + 可复现环境:chezmoi / Nix / mise / devcontainer</li><li>工作流:shell 脚本工程化 / 任务运行器 / Claude Code + tmux + fzf 联动 / 现代终端(Warp / Ghostty / WezTerm)</li></ul><p><strong>和 claudeLearning + devopsLearning 直接对齐</strong>,日常用得到、新机器半小时复刻。</p><hr><h2 id="四、贴合-claude-code-工作流的-超针对" tabindex="-1">四、贴合 Claude Code 工作流的(超针对) <a class="header-anchor" href="#四、贴合-claude-code-工作流的-超针对" aria-label="Permalink to &quot;四、贴合 Claude Code 工作流的(超针对)&quot;">​</a></h2><h3 id="k-claude-claude-anthropic-生态实战-⭐⭐⭐⭐⭐-✅-2026-05-完成-30-篇" tabindex="-1">K. claude / Claude / Anthropic 生态实战 ⭐⭐⭐⭐⭐ ✅ <strong>(2026/05 完成,30 篇)</strong> <a class="header-anchor" href="#k-claude-claude-anthropic-生态实战-⭐⭐⭐⭐⭐-✅-2026-05-完成-30-篇" aria-label="Permalink to &quot;K. claude / Claude / Anthropic 生态实战 ⭐⭐⭐⭐⭐ ✅ **(2026/05 完成,30 篇)**&quot;">​</a></h3><blockquote><p>当下日常用得到的</p></blockquote><ul><li>Claude Code 深用:Hooks / Slash Commands / MCP / Subagents / Skills / Plan Mode</li><li>Claude Agent SDK 全景</li><li>Anthropic API 高阶:Prompt Caching / Tool Use / Computer Use / Files / Citations</li><li>MCP 服务器开发(建自己的工具)</li><li>Skill 设计模式 / Agent 设计模式</li></ul><p>写下来 20-30 篇,<strong>现有 AI 系列的下游应用层</strong>,且每天用得到。</p><hr><h2 id="五、跨界-兴趣型-锦上添花" tabindex="-1">五、跨界 / 兴趣型(锦上添花) <a class="header-anchor" href="#五、跨界-兴趣型-锦上添花" aria-label="Permalink to &quot;五、跨界 / 兴趣型(锦上添花)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系列</th><th>一句话理由</th><th>推荐度</th></tr></thead><tbody><tr><td><strong>graphics / 图形学</strong></td><td>GAMES101 风格,从矩阵到光线追踪,<strong>理解 3D 引擎本质</strong></td><td>⭐⭐⭐</td></tr><tr><td><strong>interpreter / 写一个解释器</strong></td><td>Crafting Interpreters 风格,<strong>根本性提升对语言的理解</strong> ✅ <strong>(2026/05 完成,30 篇)</strong></td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>gameDev / 游戏开发</strong></td><td>Godot / Unity,独立开发者必学的&quot;娱乐性产品&quot;</td><td>⭐⭐</td></tr><tr><td><strong>mediaTech / 音视频</strong></td><td>WebRTC / FFmpeg,直播 / 实时通信 / 流媒体,<strong>冷门但工资高</strong></td><td>⭐⭐⭐</td></tr><tr><td><strong>embedded / 嵌入式</strong></td><td>ESP32 / Arduino,IoT / 智能硬件,和 Flutter 跨端做硬件 UI 能联动</td><td>⭐⭐</td></tr><tr><td><strong>indieHacker / 独立开发</strong></td><td>不是技术,是商业,<strong>0 → 第一个付费用户</strong></td><td>⭐⭐⭐</td></tr><tr><td><strong>techWriting / 技术写作 / 博客</strong></td><td>把这套笔记变成对外的输出</td><td>⭐⭐⭐</td></tr></tbody></table><hr><h2 id="推荐组合-性价比最高" tabindex="-1">推荐组合(性价比最高) <a class="header-anchor" href="#推荐组合-性价比最高" aria-label="Permalink to &quot;推荐组合(性价比最高)&quot;">​</a></h2><p><strong>如果让我选 3 个下一步动作</strong>:</p><ol><li><strong>做一个贯穿项目</strong>:用 Go/Rust + AI Infra + Data Engineering + DevOps/SRE 做完整闭环。</li><li><strong>抽一条专题线深挖</strong>:比如 graphics / mediaTech / embedded,按真实兴趣而不是知识焦虑选。</li><li><strong>把文档产品化</strong>:补索引、导航、搜索体验、系列导读和交叉链接,让 chewingdocs 更像可用知识库。</li></ol><p><strong>2026/05 新增系列状态</strong>:</p><ol><li><strong>terminalLearning</strong> ✅ 已完成 30 篇(日常用得到 + Claude Code 工作流对齐 + 新机器半小时复刻)</li><li><strong>aiInfra</strong> ✅ 已完成 30 篇(把 aiLearning + dataEngineering 接成完整 AI 工程链)</li><li><strong>mathForCS</strong> ✅ 已完成 30 篇(支撑 ai / security / algorithm 三个系列的地下室)</li></ol><p><strong>最反直觉但回报极高的</strong>:</p><ul><li><s><strong>interpreter / 写一个解释器</strong></s> ✅ <strong>(2026/05 完成,30 篇)</strong> — 现在你看 JS / Dart / Python 里所有语法都能拆成 Mochi 里写过的几十行代码。</li></ul><hr><h2 id="学习节奏建议" tabindex="-1">学习节奏建议 <a class="header-anchor" href="#学习节奏建议" aria-label="Permalink to &quot;学习节奏建议&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>连续高强度多个系列已经吃了不少认知带宽,</span></span>
<span class="line"><span>建议下一个系列前留 1-2 周做项目消化:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  做项目 = 把已学的串起来 + 暴露真实问题 + 决定下一步学什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最佳路径:</span></span>
<span class="line"><span>  一个真实项目</span></span>
<span class="line"><span>  →  Go/Rust 写核心服务</span></span>
<span class="line"><span>  →  dataEngineering 接数据链路</span></span>
<span class="line"><span>  →  aiInfra 上推理服务</span></span>
<span class="line"><span>  →  devops/SRE 做生产化</span></span>
<span class="line"><span>  →  terminalLearning 固化日常工作流</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不推荐路径:</span></span>
<span class="line"><span>  连续学 5+ 个系列不动手  → 知识不闭合,容易遗忘</span></span></code></pre></div><hr><h2 id="评分维度说明" tabindex="-1">评分维度说明 <a class="header-anchor" href="#评分维度说明" aria-label="Permalink to &quot;评分维度说明&quot;">​</a></h2><p>⭐⭐⭐⭐⭐ — 缺了之后整个体系不完整 ⭐⭐⭐⭐ — 强烈推荐学,职业天花板相关 ⭐⭐⭐ — 推荐,值得花时间 ⭐⭐ — 兴趣驱动,看个人方向</p>`,87)])])}const c=a(o,[["render",i]]);export{u as __pageData,c as default};
